"""
LDS 360 분석 엔진
엑셀 읽기 -> 계산 -> JSON 저장
"""

import pandas as pd
import numpy as np
import json
from pathlib import Path
from datetime import datetime
import config

class LDS360Analyzer:
    def __init__(self):
        self.data = None
        self.results = {}
        self.data_folder = Path("data")
        self.data_folder.mkdir(exist_ok=True)

    def load_excel(self, file_path):
        """엑셀 파일 읽기"""
        try:
            df = pd.read_excel(file_path, sheet_name=0)
            self.data = df
            return True, f"파일 로드 성공: {len(df)}행"
        except Exception as e:
            return False, f"파일 로드 실패: {str(e)}"

    def scale_5_to_100(self, score):
        """5점 척도 -> 100점 만점 변환"""
        if pd.isna(score) or score == 0:
            return None
        try:
            return round((float(score) - 1) / 4 * 100, 1)
        except:
            return None

    def extract_scores(self, row, evaluator_type):
        """각 평가자별 점수 추출"""
        scores = {}
        prefix = evaluator_type

        # 점수 열명: "{평가자}01 점수", "{평가자}02 점수" 등
        for i in range(1, 18):  # 17개 지표
            col_name = f"{prefix}{i:02d} 점수"
            if col_name in self.data.columns:
                raw_score = row[col_name]
                converted_score = self.scale_5_to_100(raw_score)
                scores[f"지표{i:02d}"] = converted_score

        return scores

    def calculate_360_average(self, person_name):
        """360도 평균 계산"""
        row = self.data[self.data['설문대상자성명'] == person_name]

        if row.empty:
            return None

        row = row.iloc[0]

        # 각 평가자별 점수
        boss_scores = self.extract_scores(row, "상사")
        peer_scores = self.extract_scores(row, "동료")
        subordinate_scores = self.extract_scores(row, "구성원")
        self_scores = self.extract_scores(row, "본인")

        # 지표별 평균 계산
        indicator_averages = {}
        for i in range(1, 18):
            key = f"지표{i:02d}"
            scores = []

            if boss_scores.get(key) is not None:
                scores.append(boss_scores[key])
            if peer_scores.get(key) is not None:
                scores.append(peer_scores[key])
            if subordinate_scores.get(key) is not None:
                scores.append(subordinate_scores[key])

            if scores:
                indicator_averages[key] = round(np.mean(scores), 1)

        # 전체 평균
        all_scores = [v for v in indicator_averages.values() if v is not None]
        overall_average = round(np.mean(all_scores), 1) if all_scores else 0

        # 360도 갭 분석 (지표별)
        gaps = {}
        for i in range(1, 18):
            key = f"지표{i:02d}"
            self_score = self_scores.get(key)
            others_avg = indicator_averages.get(key)

            if self_score is not None and others_avg is not None:
                gap = round(self_score - others_avg, 1)
                gaps[key] = {
                    "본인": self_score,
                    "타인평균": others_avg,
                    "갭": gap
                }

        return {
            "임원명": person_name,
            "조직": row.get('설문대상자조직', 'N/A'),
            "직책": row.get('설문대상자직책', 'N/A'),
            "전체평균": overall_average,
            "지표별평균": indicator_averages,
            "평가자별": {
                "상사": boss_scores,
                "동료": peer_scores,
                "부하": subordinate_scores,
                "본인": self_scores
            },
            "360도갭": gaps
        }

    def analyze_all(self):
        """전체 데이터 분석"""
        if self.data is None:
            return False, "데이터가 로드되지 않았습니다"

        results = {}
        names = self.data['설문대상자성명'].unique()

        for name in names:
            if pd.isna(name):
                continue
            result = self.calculate_360_average(name)
            if result:
                results[name] = result

        self.results = results
        return True, f"{len(results)}명 분석 완료"

    def save_json(self, filename=None):
        """결과를 JSON으로 저장"""
        if not self.results:
            return False, "분석 결과가 없습니다"

        if filename is None:
            filename = f"lds360_analysis_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json"

        file_path = self.data_folder / filename

        try:
            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(self.results, f, ensure_ascii=False, indent=2)
            return True, f"저장 성공: {file_path}"
        except Exception as e:
            return False, f"저장 실패: {str(e)}"

    def load_json(self, filename):
        """JSON에서 결과 로드"""
        file_path = self.data_folder / filename

        try:
            with open(file_path, 'r', encoding='utf-8') as f:
                self.results = json.load(f)
            return True, f"로드 성공: {filename}"
        except Exception as e:
            return False, f"로드 실패: {str(e)}"

    def get_summary(self):
        """분석 요약 반환"""
        if not self.results:
            return None

        names = list(self.results.keys())
        overall_averages = [v['전체평균'] for v in self.results.values()]

        return {
            "총인원": len(names),
            "임원명_목록": names,
            "평균점수_전체": round(np.mean(overall_averages), 1),
            "최고점수": round(np.max(overall_averages), 1),
            "최저점수": round(np.min(overall_averages), 1),
            "표준편차": round(np.std(overall_averages), 1)
        }

