"""
LDS 360 유틸 함수
데이터 처리 및 포매팅 헬퍼
"""

import pandas as pd
import numpy as np
from datetime import datetime
import json

class DataProcessor:
    """데이터 처리 유틸 클래스"""

    @staticmethod
    def scale_5_to_100(score):
        """5점 척도를 100점 만점으로 변환"""
        if pd.isna(score) or score == 0:
            return None
        try:
            return round((float(score) - 1) / 4 * 100, 1)
        except:
            return None

    @staticmethod
    def calculate_average(scores):
        """점수 리스트의 평균 계산 (None 제외)"""
        valid_scores = [s for s in scores if s is not None]
        if not valid_scores:
            return None
        return round(np.mean(valid_scores), 1)

    @staticmethod
    def categorize_score(score):
        """점수를 등급으로 분류"""
        if score is None:
            return "평가안함"
        elif score >= 80:
            return "우수"
        elif score >= 60:
            return "보통"
        else:
            return "개선필요"

    @staticmethod
    def get_risk_level(score):
        """리스크 레벨 판정"""
        if score >= 80:
            return "낮음"
        elif score >= 60:
            return "중간"
        else:
            return "높음"

class ChartFormatter:
    """차트 포매팅 유틸 클래스"""

    @staticmethod
    def format_number(value, decimals=1):
        """숫자 포매팅"""
        if value is None:
            return "—"
        return f"{value:.{decimals}f}"

    @staticmethod
    def get_color_for_score(score):
        """점수에 따른 색상 반환 (RGB)"""
        if score is None:
            return "#cccccc"
        elif score >= 80:
            return "#4caf50"  # 녹색
        elif score >= 60:
            return "#ff9800"  # 주황색
        else:
            return "#f44336"  # 빨강색

    @staticmethod
    def create_radar_data(scores_dict):
        """방사형 차트용 데이터 생성"""
        labels = list(scores_dict.keys())
        values = list(scores_dict.values())
        return labels, values

class ExcelProcessor:
    """엑셀 파일 처리 특화 유틸"""

    @staticmethod
    def validate_columns(df, required_cols):
        """필수 컬럼 존재 여부 확인"""
        missing = [col for col in required_cols if col not in df.columns]
        if missing:
            return False, f"누락된 컬럼: {', '.join(missing)}"
        return True, "컬럼 검증 성공"

    @staticmethod
    def clean_data(df):
        """데이터 정제"""
        # 빈 행 제거
        df = df.dropna(subset=['설문대상자성명'])

        # 중복 제거
        df = df.drop_duplicates(subset=['설문대상자성명'])

        return df

    @staticmethod
    def extract_evaluation_columns(df, evaluator_type, num_indicators=17):
        """평가자별 점수 컬럼 추출"""
        cols = []
        for i in range(1, num_indicators + 1):
            col_name = f"{evaluator_type}{i:02d} 점수"
            if col_name in df.columns:
                cols.append(col_name)
        return cols

class ReportGenerator:
    """리포트 생성 유틸"""

    @staticmethod
    def generate_summary_text(results_dict):
        """요약 텍스트 생성"""
        if not results_dict:
            return "분석 결과 없음"

        names = list(results_dict.keys())
        scores = [v['전체평균'] for v in results_dict.values()]

        summary = f"""
## 📊 분석 요약

**분석 대상**: {len(names)}명
**평균 점수**: {np.mean(scores):.1f}
**최고 점수**: {np.max(scores):.1f}
**최저 점수**: {np.min(scores):.1f}
**표준편차**: {np.std(scores):.1f}

**분석 일시**: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}
        """
        return summary

    @staticmethod
    def generate_individual_report(name, result):
        """개인별 보고서 생성"""
        report = f"""
# {name}의 리더십 평가 보고서

## 기본 정보
- **성명**: {name}
- **조직**: {result.get('조직', 'N/A')}
- **직책**: {result.get('직책', 'N/A')}

## 전체 평가
- **전체 점수**: {result['전체평균']:.1f}/100

## 지표별 점수
| 지표 | 점수 | 평가 |
|------|------|------|
"""
        for i in range(1, 18):
            key = f'지표{i:02d}'
            score = result['지표별평균'].get(key, 0)
            category = DataProcessor.categorize_score(score)
            report += f"| 지표 {i} | {score:.1f} | {category} |\n"

        return report

class ValidationHelper:
    """검증 헬퍼"""

    @staticmethod
    def validate_score(score):
        """점수 유효성 검증"""
        try:
            score = float(score)
            return 0 <= score <= 100
        except:
            return False

    @staticmethod
    def validate_name(name):
        """이름 유효성 검증"""
        if not name or pd.isna(name):
            return False
        return len(str(name).strip()) > 0

    @staticmethod
    def get_validation_status(df):
        """전체 데이터 검증 상태"""
        issues = []

        # 필수 컬럼 확인
        required = ['설문대상자성명', '설문대상자조직', '설문대상자직책']
        for col in required:
            if col not in df.columns:
                issues.append(f"필수 컬럼 누락: {col}")

        # 빈 행 확인
        if df['설문대상자성명'].isna().any():
            issues.append("임원명이 없는 행이 있습니다")

        # 점수 컬럼 확인
        score_cols = [col for col in df.columns if '점수' in col]
        if not score_cols:
            issues.append("점수 컬럼을 찾을 수 없습니다")

        return {
            "valid": len(issues) == 0,
            "issues": issues,
            "total_rows": len(df),
            "valid_rows": len(df.dropna(subset=['설문대상자성명']))
        }

